INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100101, 27, "東山奈央", "A", "トゥインクルウィッシュ", "ヒヨリ", "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 155, 16, 0, 8, 2, "獣人族", "人助けが大好き！　前向き格闘娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100201, 5, "種田梨沙", "O", "トゥインクルウィッシュ", "ユイ", "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 158, 17, 0, 4, 2, "ヒューマン", "戦闘のサポートが得意な、心優しい少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100301, 12, "早見沙織", "B", "トゥインクルウィッシュ", "レイ", "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 163, 18, 0, 1, 2, "魔族", "クールで何事にも真っ直ぐな剣士");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100401, 10, "諸星すみれ", "O", "リトルリリカル", "ミソギ", "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 27, 128, 9, 0, 8, 5, "ヒューマン", "探検好きのイタズラっ子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100501, 25, "下田麻美", "O", "王宮騎士団（NIGHTMARE）", "マツリ", "ヒーローごっこ", "？？？", 40, 146, 12, 0, 11, 8, "獣人族", "ヒーローに憧れる騎士見習いの少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100601, 22, "浅倉杏美", "O", "悪魔偽王国軍（ディアボロス）", "アカリ", "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 42, 150, 13, 0, 11, 7, "魔族", "甘え上手なみんなの人気者");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100701, 23, "雨宮天", "B", "悪魔偽王国軍（ディアボロス）", "ミヤコ", "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, 130, 14, 0, 1, 7, "魔族", "プリン大好きゴースト娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100801, 10, "大空直美", "AB", "ヴァイスフリューゲル　ランドソル支部", "ユキ", "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, 150, 14, 0, 10, 15, "エルフ", "ボクは誰よりも美しい");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100901, 5, "髙野麻美", "A", "トワイライトキャラバン", "アンナ", "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 45, 159, 17, 0, 7, 13, "魔族", "前世を信じる中二病患者、「疾風の冥姫」");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101001, 22, "内田真礼", "O", "自警団（カォン）", "マホ", "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 42, 155, 16, 0, 9, 10, "獣人族", "マホマホ王国のプリンセス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101101, 25, "阿澄佳奈", "A", "ラビリンス", "リノ", "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 44, 156, 15, 0, 8, 3, "ヒューマン", "人懐っこくてマシンガントークな妹系少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101201, 24, "大橋彩香", "A", "フォレスティエ", "ハツネ", "妹と遊ぶこと、二度寝、昼寝、早寝", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 46, 156, 17, 0, 12, 6, "エルフ", "みんなのために超能力を使う眠り姫");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101301, 21, "佳村はるか", "O", "トワイライトキャラバン", "ナナカ", "読書、魔法", "", 55, 166, 18, 0, 8, 13, "魔族", "オタク全開な魔法少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101401, 3, "水瀬いのり", "AB", "自警団（カォン）", "カスミ", "読書、推理", "test", 41, 152, 15, 0, 11, 10, "獣人族", "頭脳明晰な美少女名探偵");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101501, 5, "國府田マリ子", "O", "フォレスティエ", "ミサト", "絵本作り", "test", 54, 165, 21, 0, 9, 6, "エルフ", "母性溢れる優しいみんなの「ミサト先生」");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101601, 10, "上坂すみれ", "O", "ルーセント学院", "スズナ", "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 48, 167, 17, 0, 4, 14, "魔族", "天真爛漫で人気者のカリスマモデル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101701, 7, "高森奈津美", "A", "自警団（カォン）", "カオリ", "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 53, 158, 17, 0, 7, 10, "獣人族", "いつでも「なんくるないさ～」な天然娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101801, 14, "伊藤静", "B", "ルーセント学院", "イオ", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 52, 162, 23, 0, 8, 14, "魔族", "多くの男性を魅了する無垢な女教師");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102001, 3, "日高里菜", "O", "リトルリリカル", "ミミ", "かわいいもの集め", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 21, 117, 10, 0, 4, 5, "獣人族", "お歌もにんじんも、ウサギさんも大好き♪");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102101, 9, "植田佳奈", "B", "サレンディア救護院", "クルミ", "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, 150, 12, 0, 6, 9, "ヒューマン", "泣き虫で臆病な守ってあげたい女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102201, 22, "原紗友里", "O", "悪魔偽王国軍（ディアボロス）", "ヨリ", "ゲーム全般", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 40, 150, 13, 0, 11, 7, "魔族", "人見知りであまのじゃくな女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102301, 10, "芹澤優", "B", "サレンディア救護院", "アヤネ", "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, 148, 14, 0, 5, 9, "ヒューマン", "ぷうきちといつも一緒！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102501, 12, "悠木碧", "O", "サレンディア救護院", "スズメ", "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 43, 154, 15, 0, 12, 9, "ヒューマン", "お嬢さまのためにがんばるドジっ娘メイド");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102601, 1, "小岩井ことり", "B", "牧場（エリザベスパーク）", "リン", "あんパン", "test", 42, 144, 17, 0, 1, 11, "獣人族", "遊びと睡眠が何より大事なぐうたら娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102701, 30, "橋本ちなみ", "B", "トワイライトキャラバン", "エリコ", "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 154, 16, 0, 7, 13, "魔族", "運命の相手に一途すぎる乙女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102801, 4, "堀江由衣", "A", "サレンディア救護院", "サレン", "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 43, 156, 17, 0, 10, 9, "エルフ", "救護院を経営する優しい庶民派お嬢様");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102901, 24, "日笠陽子", "B", "カルミナ", "ノゾミ", "舞台鑑賞、ダンス", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 40, 157, 17, 0, 1, 4, "ヒューマン", "歌って踊れる大人気アイドル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103001, 31, "佐藤聡美", "O", "ヴァイスフリューゲル　ランドソル支部", "ニノン", "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, 163, 16, 0, 8, 15, "ヒューマン", "トーゴクの神秘、オシエテクダサイ！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103101, 22, "大坪由佳", "AB", "悪魔偽王国軍（ディアボロス）", "シノブ", "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 157, 18, 0, 12, 7, "魔族", "占いが得意な霊能少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103201, 12, "松嵜麗", "AB", "メルクリウス財団", "アキノ", "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 45, 157, 18, 0, 3, 12, "ヒューマン", "一人前の商人を目指すパワフルお嬢様");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103301, 3, "新田恵海", "B", "牧場（エリザベスパーク）", "マヒル", "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 35, 142, 20, 0, 3, 11, "ヒューマン", "みんなを笑顔にするお笑い牧場主");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103401, 16, "今井麻美", "A", "メルクリウス財団", "ユカリ", "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 55, 164, 22, 0, 3, 12, "エルフ", "純情でほっとけない大人の女性");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103601, 2, "小倉唯", "A", "リトルリリカル", "キョウカ", "お勉強", "test", 21, 118, 8, 0, 2, 5, "エルフ", "礼儀正しくしっかり者のちびっ子優等生");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103701, 11, "茅原実里", "A", "王宮騎士団（NIGHTMARE）", "トモ", "剣術、年長者をからかう", "test", 43, 149, 13, 0, 8, 8, "ヒューマン", "義理堅くてからかい好きな剣術少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103801, 3, "小清水亜美", "A", "牧場（エリザベスパーク）", "シオリ", "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 40, 153, 14, 0, 11, 11, "獣人族", "読書が趣味の病弱少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104001, 6, "花澤香菜", "AB", "フォレスティエ", "アオイ", "友達作りのイメトレ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 44, 158, 13, 0, 6, 6, "エルフ", "「友達」に憧れる、エルフの森の女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104201, 3, "福原綾香", "O", "カルミナ", "チカ", "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 163, 17, 0, 6, 4, "ヒューマン", "人々を守るために歌う、唱喚士の少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104301, 9, "小松未可子", "O", "自警団（カォン）", "マコト", "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 54, 168, 17, 0, 8, 10, "獣人族", "男勝りで情に厚いワイルド娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104401, 5, "丹下桜", "A", "悪魔偽王国軍（ディアボロス）", "イリヤ", "世界征服", "test", 50, 172, "??", 0, 5, 7, "魔族", "かつては夜を支配した最強の吸血鬼");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104501, 19, "長妻樹里", "AB", "ヴァイスフリューゲル　ランドソル支部", "クウカ", "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 49, 157, 18, 0, 11, 15, "ヒューマン", "妄想大好き！　ほんとは照れ屋な女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104601, 1, "沼倉愛美", "AB", "メルクリウス財団", "タマキ", "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 158, 19, 0, 3, 12, "獣人族", "弱きを助け強きをくじく猫娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104701, 25, "川澄綾子", "A", "王宮騎士団（NIGHTMARE）", "ジュン", "格闘技、湯浴み", "？？？", 50, 171, 25, 0, 10, 8, "ヒューマン", "素顔を見せない冷静沈着な女性騎士");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104801, 11, "田所あずさ", "O", "メルクリウス財団", "ミフユ", "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 163, 20, 0, 11, 12, "ヒューマン", "仕事も私事も効率優先な傭兵少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104901, 24, "生天目仁美", "O", "ラビリンス", "シズル", "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 168, 18, 0, 10, 3, "ヒューマン", "お姉ちゃんがお世話してあげるからねっ！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105001, 3, "久野美咲", "A", "ルーセント学院", "ミサキ", "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 22, 120, 11, 0, 1, 14, "魔族", "ちょっとおませな恋に恋する女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105101, 7, "三石琴乃", "A", "トワイライトキャラバン", "ミツキ", "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 53, 166, 27, 0, 3, 13, "ヒューマン", "実験が趣味の危険な科学者");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105201, 14, "徳井青空", "A", "牧場（エリザベスパーク）", "リマ", "毛繕い、お喋り", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 100, 150, 17, 0, 3, 11, "獣人族", "乙女チックなもふもふアニマル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105301, 28, "辻あゆみ", "A", "ヴァイスフリューゲル　ランドソル支部", "モニカ", "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 33, 140, 17, 0, 7, 15, "ヒューマン", "見た目も中身もお子ちゃまな異国の軍人");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105401, 7, "木戸衣吹", "AB", "カルミナ", "ツムギ", "裁縫", "test", 45, 153, 14, 0, 9, 4, "ヒューマン", "ファッション大好きなキュートガール");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105501, 7, "大関英里", "O", "ヴァイスフリューゲル　ランドソル支部", "アユミ", "観察", "test", 43, 155, 16, 0, 4, 15, "エルフ", "どこまでも一途に慕う、純情乙女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105601, 11, "佐藤利奈", "B", "トワイライトキャラバン", "ルカ", "釣り", "test", 54, 167, 25, 0, 7, 13, "ヒューマン", "人情味溢れる粋でいなせな「姉御」");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105701, 10, "金元寿子", "O", "？？？", "ジータ", "冒険、おしゃべり", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 45, 156, 17, 0, 3, "", "ヒューマン", "空への冒険を夢見る騎空士の少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105801, 31, "M・A・O", "O", "美食殿", "ペコリーヌ", "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 46, 156, 17, 0, 3, 1, "ヒューマン", "いつも元気な腹ペコ少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105901, 11, "伊藤美来", "B", "美食殿", "コッコロ", "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 35, 140, 11, 0, 5, 1, "エルフ", "主を慕う、小さなガイド役");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106001, 2, "立花理香", "A", "美食殿", "キャル", "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 39, 152, 14, 0, 9, 1, "獣人族", "行き倒れの謎のネコミミ魔法使い");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106101, 11, "潘めぐみ", "O", "？？？", "ムイミ", "冒険、思い出話", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 40, 148, 16, 0, 8, "", "ヒューマン", "さまよえる謎の少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106301, 17, "優木かな", "O", "？？？", "アリサ", "キレイな葉っぱを集めること", "", 42, 155, 15, 0, 6, "", "エルフ", "森番を目指すエルフの少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106401, 14, "近藤玲奈", "B", "美食殿", "シェフィ", "読書、ストレッチ", "", "???", 147, 14, 0, 12, 1, "ドラゴン族", "記憶喪失のドラゴン娘");
