INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106601, 29, "藤田茜", "AB", "ドラゴンズネスト", "イノリ", "ゲーム", "", "???", 145, 13, 0, 9, 17, "ドラゴン族", "口が達者なヘタレドラゴン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106701, 17, "大西沙織", "O", "ドラゴンズネスト", "ホマレ", "絵画、読書", "", "???", 168, 25, 0, 4, 17, "ドラゴン族", "妖しい微笑で全てを見透かす臥竜の頭領");
