INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107001, 24, "井口裕香", "O", "？？？", "ネネカ", "物真似、芸術鑑賞", "", "??", 149, 24, 0, 3, "", "エルフ", "研究所に隠れ住む物静かなお姉さん");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107101, 7, "たかはし智秋", "O", "王宮騎士団（NIGHTMARE）", "クリスティーナ", "強敵との闘争", "", "??", 165, 27, 0, 2, 8, "ヒューマン", "傍若無人な王宮騎士団副団長");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107501, 31, "M・A・O", "O", "美食殿", "ペコリーヌ（サマー）", "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 46, 156, 17, 0, 3, 1, "ヒューマン", "いつも元気な腹ペコ少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107601, 11, "伊藤美来", "B", "美食殿", "コッコロ（サマー）", "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 35, 140, 11, 0, 5, 1, "エルフ", "主を慕う、小さなガイド役");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107701, 12, "悠木碧", "O", "サレンディア救護院", "スズメ（サマー）", "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 43, 154, 15, 0, 12, 9, "ヒューマン", "お嬢さまのためにがんばるドジっ娘メイド");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107801, 2, "立花理香", "A", "美食殿", "キャル（サマー）", "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 39, 152, 14, 0, 9, 1, "獣人族", "行き倒れの謎のネコミミ魔法使い");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107901, 1, "沼倉愛美", "AB", "メルクリウス財団", "タマキ（サマー）", "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 158, 19, 0, 3, 12, "獣人族", "弱きを助け強きをくじく猫娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108001, 11, "田所あずさ", "O", "メルクリウス財団", "ミフユ（サマー）", "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 163, 20, 0, 11, 12, "ヒューマン", "仕事も私事も効率優先な傭兵少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108101, 22, "大坪由佳", "AB", "悪魔偽王国軍（ディアボロス）", "シノブ（ハロウィン）", "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 157, 18, 0, 12, 7, "魔族", "占いが得意な霊能少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108201, 23, "雨宮天", "B", "悪魔偽王国軍（ディアボロス）", "ミヤコ（ハロウィン）", "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, 130, 14, 0, 1, 7, "魔族", "プリン大好きゴースト娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108301, 3, "久野美咲", "A", "ルーセント学院", "ミサキ（ハロウィン）", "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 22, 120, 11, 0, 1, 14, "魔族", "ちょっとおませな恋に恋する女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108401, 3, "福原綾香", "O", "カルミナ", "チカ（クリスマス）", "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 163, 17, 0, 6, 4, "ヒューマン", "人々を守るために歌う、唱喚士の少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108501, 9, "植田佳奈", "B", "サレンディア救護院", "クルミ（クリスマス）", "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, 150, 12, 0, 6, 9, "ヒューマン", "泣き虫で臆病な守ってあげたい女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108601, 10, "芹澤優", "B", "サレンディア救護院", "アヤネ（クリスマス）", "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, 148, 14, 0, 5, 9, "ヒューマン", "ぷうきちといつも一緒！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108701, 27, "東山奈央", "A", "トゥインクルウィッシュ", "ヒヨリ（ニューイヤー）", "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 155, 16, 0, 8, 2, "獣人族", "人助けが大好き！　前向き格闘娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108801, 5, "種田梨沙", "O", "トゥインクルウィッシュ", "ユイ（ニューイヤー）", "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 158, 17, 0, 4, 2, "ヒューマン", "戦闘のサポートが得意な、心優しい少女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108901, 12, "早見沙織", "B", "トゥインクルウィッシュ", "レイ（ニューイヤー）", "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 163, 18, 0, 1, 2, "魔族", "クールで何事にも真っ直ぐな剣士");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109001, 30, "橋本ちなみ", "B", "トワイライトキャラバン", "エリコ（バレンタイン）", "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 154, 16, 0, 7, 13, "魔族", "運命の相手に一途すぎる乙女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109101, 24, "生天目仁美", "O", "ラビリンス", "シズル（バレンタイン）", "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 168, 18, 0, 10, 3, "ヒューマン", "お姉ちゃんがお世話してあげるからねっ！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109201, 1, "日笠陽子", "AB", "？？？", "アン", "読書", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 55, 156, 17, 0, 12, "", "ヒューマン", "英霊と契約を結んだマナリアの天才王女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109301, 4, "こやまきみこ", "O", "？？？", "ルゥ", "食べること、眠ること", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 45, 144, 16, 0, 2, "", "ヒューマン", "マナリア魔法学院の新入生");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109401, 3, "福原綾香", "B", "？？？", "グレア", "ピアノ", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 67, 167, 17, 0, 11, "", "半人半竜", "人を超越した力を有す心優しい竜姫");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109501, 19, "長妻樹里", "AB", "ヴァイスフリューゲル　ランドソル支部", "クウカ（オーエド）", "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 49, 157, 18, 0, 11, 15, "ヒューマン", "妄想大好き！　ほんとは照れ屋な女の子");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109601, 31, "佐藤聡美", "O", "ヴァイスフリューゲル　ランドソル支部", "ニノン（オーエド）", "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, 163, 16, 0, 8, 15, "ヒューマン", "トーゴクの神秘、オシエテクダサイ！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109701, 2, "水瀬いのり", "?", "？？？", "レム", "演劇鑑賞、詩文", "", "??", 154, 17, 0, 2, "", "鬼族", "鬼がかりの万能妹メイド");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109801, 2, "村川梨衣", "?", "？？？", "ラム", "読書", "", "??", 154, 17, 0, 2, "", "鬼族", "毒舌系鬼姉メイド");
