INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115501, 11, "伊藤美来", "B", "美食殿", "コッコロ（儀装束）", "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 35, 140, 11, 0, 5, 1, "エルフ", "主を慕う、小さなガイド役");
