INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115901, 9, "小松未可子", "O", "自警団（カォン）", "マコト（シンデレラ）", "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 54, 168, 17, 0, 8, 10, "獣人族", "男勝りで情に厚いワイルド娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116001, 22, "内田真礼", "O", "自警団（カォン）", "マホ（シンデレラ）", "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 42, 155, 16, 0, 9, 10, "獣人族", "マホマホ王国のプリンセス");
