INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116801, 1, "沼倉愛美", "AB", "メルクリウス財団", "タマキ（作業服）", "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 158, 19, 0, 3, 12, "獣人族", "弱きを助け強きをくじく猫娘");
