INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117001, 30, "橋本ちなみ", "B", "トワイライトキャラバン", "エリコ（サマー）", "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 154, 16, 0, 7, 13, "魔族", "運命の相手に一途すぎる乙女");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117101, 24, "生天目仁美", "O", "ラビリンス", "シズル（サマー）", "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 168, 18, 0, 10, 3, "ヒューマン", "お姉ちゃんがお世話してあげるからねっ！");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117201, 24, "日笠陽子", "B", "カルミナ", "ノゾミ（サマー）", "舞台鑑賞、ダンス", "", 40, 157, 17, 0, 1, 4, "ヒューマン", "歌って踊れる大人気アイドル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117301, 3, "福原綾香", "O", "カルミナ", "チカ（サマー）", "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 163, 17, 0, 6, 4, "ヒューマン", "人々を守るために歌う、唱喚士の少女");
