INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117601, 10, "大空直美", "AB", "ヴァイスフリューゲル　ランドソル支部", "ユキ（オーエド）", "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, 150, 14, 0, 10, 15, "エルフ", "ボクは誰よりも美しい");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117701, 7, "高森奈津美", "A", "自警団（カォン）", "カオリ（ハロウィン）", "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 53, 158, 17, 0, 7, 10, "獣人族", "いつでも「なんくるないさ～」な天然娘");
