INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122201, 16, "今井麻美", "A", "メルクリウス財団", "ユカリ（キャンプ）", "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 55, 164, 22, 0, 3, 12, "エルフ", "純情でほっとけない大人の女性");
