INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122401, 27, "東山奈央", "A", "トゥインクルウィッシュ", "ヒヨリ（サマー）", "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 155, 16, 0, 8, 2, "獣人族", "人助けが大好き！　前向き格闘娘");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122501, 12, "早見沙織", "B", "トゥインクルウィッシュ", "レイ（サマー）", "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 163, 18, 0, 1, 2, "魔族", "クールで何事にも真っ直ぐな剣士");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122601, 5, "種田梨沙", "O", "トゥインクルウィッシュ", "ユイ（サマー）", "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 158, 17, 0, 4, 2, "ヒューマン", "戦闘のサポートが得意な、心優しい少女");
