INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122801, 10, "諸星すみれ", "O", "リトルリリカル", "ミソギ（サマー）", "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 27, 128, 9, 0, 8, 5, "ヒューマン", "探検好きのイタズラっ子");
